/**
 * Generates a human-readable slug from three word categories.
 * Falls back to a timestamp-based string if word generation fails.
 */
export const generateSlug = (): string => {
  const adjectives = [
    'amber', 'brave', 'calm', 'deft', 'eager', 'fair',
    'grand', 'hazy', 'idle', 'jovial', 'keen', 'lush',
    'mild', 'noble', 'odd', 'prime', 'quick', 'rare',
    'sharp', 'tidy',
  ];

  const colors = [
    'azure', 'beige', 'coral', 'denim', 'ecru', 'fawn',
    'gold', 'hazel', 'ivory', 'jade', 'khaki', 'lemon',
    'mauve', 'navy', 'olive', 'plum', 'ruby', 'sage',
    'teal', 'umber',
  ];

  const nouns = [
    'anchor', 'bridge', 'creek', 'delta', 'echo', 'fjord',
    'grove', 'haven', 'inlet', 'jetty', 'knoll', 'lagoon',
    'mesa', 'nook', 'oasis', 'peak', 'quay', 'ridge',
    'shore', 'tide',
  ];

  try {
    const adj = adjectives[Math.floor(Math.random() * adjectives.length)];
    const color = colors[Math.floor(Math.random() * colors.length)];
    const noun = nouns[Math.floor(Math.random() * nouns.length)];
    return `${adj}-${color}-${noun}`;
  } catch {
    return Date.now().toString();
  }
};


